"""Base class for firmware version-specific handlers"""

from abc import ABC, abstractmethod


class FirmwareHandler(ABC):
    """Abstract base class for firmware-specific implementations.

    Each firmware version may have different:
    - Page paths
    - Form field names
    - HTML structure
    - Form submission requirements

    Subclasses implement version-specific logic.
    """

    def __init__(self):
        self.version = "unknown"

    @abstractmethod
    def get_page_paths(self):
        """Return dictionary of page paths for this firmware version.

        Returns:
            Dict mapping page names to paths, e.g.:
            {
                'dhcp': '/cgi-bin/dhcpserver.ha',
                'ipalloc': '/cgi-bin/ipalloc.ha',
                'wifi': '/cgi-bin/wifi.ha',
            }
        """
        pass

    @abstractmethod
    def parse_dhcp_page(self, html):
        """Parse DHCP server configuration page.

        Args:
            html: HTML content from dhcpserver.ha

        Returns:
            Dictionary with parsed DHCP configuration
        """
        pass

    @abstractmethod
    def parse_ipalloc_page(self, html):
        """Parse IP allocation table page.

        Args:
            html: HTML content from ipalloc.ha

        Returns:
            Dictionary with parsed IP allocation data
        """
        pass

    def get_dhcp_page_path(self):
        """Get path to DHCP configuration page."""
        return self.get_page_paths().get('dhcp', '/cgi-bin/dhcpserver.ha')

    def get_ipalloc_page_path(self):
        """Get path to IP allocation page."""
        return self.get_page_paths().get('ipalloc', '/cgi-bin/ipalloc.ha')

    def get_sysinfo_page_path(self):
        """Get path to system info page."""
        return self.get_page_paths().get('sysinfo', '/cgi-bin/sysinfo.ha')
